// Parse Contradiction Tool Calls — Phase 3 task 3.6
// Fan out one model response into N tool-call items.

const response = $input.all()[0]?.json;
const request = $('Build Contradiction Request').all()[0]?.json;
if (!response) throw new Error('Parse Contradiction Tool Calls received 0 input items.');
if (!request) throw new Error('Build Contradiction Request item unavailable.');

const message = response.choices?.[0]?.message || {};
const toolCalls = Array.isArray(message.tool_calls) ? message.tool_calls : [];

let assistantContent = message.content;
if (Array.isArray(assistantContent)) {
  assistantContent = assistantContent.map((p) => p?.text || '').join('');
}
if (toolCalls.length === 0) {
  throw new Error(`Contradiction turn-1 returned no tool_calls. D-2 tool-use likely failed. Raw content: ${String(assistantContent || '').slice(0, 500)}`);
}

const out = [];
for (const call of toolCalls) {
  if (call?.type !== 'function' || call?.function?.name !== 'retrieve_document') continue;

  let args;
  try {
    args = JSON.parse(call.function.arguments || '{}');
  } catch (err) {
    throw new Error(`Failed to parse retrieve_document arguments: ${err.message}\nRaw: ${call.function.arguments || ''}`);
  }

  const sourceName = typeof args.source_name === 'string' ? args.source_name.trim() : '';
  const query = typeof args.query === 'string' ? args.query.trim() : '';
  const kRaw = typeof args.k === 'number' ? args.k : parseInt(args.k, 10);
  const k = Number.isFinite(kRaw) ? Math.max(1, Math.min(5, kRaw)) : 5;

  if (!sourceName) throw new Error('retrieve_document tool call missing source_name');
  if (!query) throw new Error('retrieve_document tool call missing query');

  out.push({
    json: {
      ...request,
      turn1_message: {
        role: 'assistant',
        content: typeof assistantContent === 'string' ? assistantContent : null,
        tool_calls: toolCalls,
      },
      tool_call_id: call.id,
      source_name: sourceName,
      query,
      k,
    },
  });
}

if (out.length === 0) {
  throw new Error('No usable retrieve_document tool calls found in turn-1 response.');
}

return out;

// Rank Contradiction Chunks — Phase 3 task 3.6
// Implements the retrieve_document tool against the existing aggregate chunk store.

const response = $input.item.json;
const req = $('Parse Contradiction Tool Calls').item.json;
const store = $('Aggregate Vector Store').all()[0]?.json;
if (!store) throw new Error('Aggregate Vector Store item unavailable in Rank Contradiction Chunks.');

const queryEmbedding = response.data?.[0]?.embedding;
if (!Array.isArray(queryEmbedding) || queryEmbedding.length === 0) {
  throw new Error(`No contradiction query embedding returned for ${req.source_name}`);
}

function cosineSimilarity(a, b) {
  let dot = 0;
  let normA = 0;
  let normB = 0;
  const len = Math.min(a.length, b.length);
  for (let i = 0; i < len; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  if (normA === 0 || normB === 0) return -1;
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

const ranked = (store.chunks || [])
  .filter((c) => c.source_name === req.source_name && Array.isArray(c.embedding) && c.embedding.length > 0)
  .map((c) => ({
    score: cosineSimilarity(queryEmbedding, c.embedding),
    chunk: {
      source_name: c.source_name,
      page_estimate: c.page_estimate,
      chunk_index: c.chunk_index,
      text: c.text,
    },
  }))
  .sort((a, b) => b.score - a.score)
  .slice(0, req.k)
  .map((r) => r.chunk);

return {
  json: {
    ...req,
    tool_result: {
      source_name: req.source_name,
      query: req.query,
      chunks: ranked,
    },
    query_embedding_tokens: response.usage?.prompt_tokens || 0,
  },
};

// Aggregate Contradiction Tool Results — Phase 3 task 3.6
// Reconstruct the tool conversation messages for the final synthesis turn.

const items = $input.all();
if (items.length === 0) throw new Error('Aggregate Contradiction Tool Results received 0 tool results.');

const first = items[0].json;
const toolMessages = items.map((item) => ({
  role: 'tool',
  tool_call_id: item.json.tool_call_id,
  name: 'retrieve_document',
  content: JSON.stringify(item.json.tool_result),
}));
const totalQueryTokens = items.reduce((acc, item) => acc + (item.json.query_embedding_tokens || 0), 0);

return {
  json: {
    run_id: first.run_id,
    deal_id: first.deal_id,
    company_name: first.company_name,
    timestamp_started: first.timestamp_started,
    source_manifest: first.source_manifest,
    extraction_outputs: first.extraction_outputs,
    system_prompt: first.system_prompt,
    user_message: first.user_message,
    turn1_message: first.turn1_message,
    messages: [
      { role: 'system', content: first.system_prompt },
      { role: 'user', content: first.user_message },
      {
        role: 'assistant',
        content: first.turn1_message?.content ?? null,
        tool_calls: first.turn1_message?.tool_calls || [],
      },
      ...toolMessages,
    ],
    contradiction_retrieval_meta: {
      tool_call_count: items.length,
      total_query_embedding_tokens: totalQueryTokens,
      tool_results: items.map((item) => item.json.tool_result),
    },
  },
};

// Parse Contradiction Response — Phase 3 task 3.6
// Normalize the final tool-use synthesis into the exact Contradiction schema shape.

const response = $input.item.json;
const request = $('Aggregate Contradiction Tool Results').item.json;

let content = response.choices?.[0]?.message?.content;
if (Array.isArray(content)) {
  content = content.map((p) => p?.text || '').join('');
}
if (typeof content !== 'string' || !content.trim()) {
  throw new Error('Contradiction final response missing message content.');
}

content = content.trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (err) {
  throw new Error(`Contradiction JSON parse failed: ${err.message}\nRaw content: ${content.slice(0, 500)}`);
}

function obj(v) {
  return v && typeof v === 'object' && !Array.isArray(v) ? v : {};
}
function str(v) {
  return typeof v === 'string' ? v : null;
}
function stringArray(v) {
  return Array.isArray(v) ? v.filter((x) => typeof x === 'string') : [];
}
function validSeverity(v) {
  return ['HIGH', 'MEDIUM', 'LOW'].includes(v) ? v : null;
}
function validContradictionClass(v) {
  return ['DISPUTED', 'UNSUPPORTED'].includes(v) ? v : null;
}
function validVerifiedClass(v) {
  return ['CORROBORATED', 'UNCONTRADICTED'].includes(v) ? v : null;
}

const contradictions = Array.isArray(parsed.contradictions)
  ? parsed.contradictions
      .map((x) => obj(x))
      .map((x) => ({
        claim: str(x.claim),
        sources_making_claim: stringArray(x.sources_making_claim),
        contradicting_evidence: Array.isArray(x.contradicting_evidence)
          ? x.contradicting_evidence
              .map((e) => obj(e))
              .map((e) => ({
                source: str(e.source),
                citation: str(e.citation),
                evidence: str(e.evidence),
              }))
              .filter((e) => e.source && e.citation && e.evidence)
          : [],
        nature_of_conflict: str(x.nature_of_conflict) || '',
        severity: validSeverity(x.severity),
        classification: validContradictionClass(x.classification),
      }))
      .filter((x) => x.claim && x.sources_making_claim.length > 0 && x.severity && x.classification)
      .filter((x) => x.classification !== 'DISPUTED' || x.contradicting_evidence.length > 0)
  : [];

const verifiedClaims = Array.isArray(parsed.verified_claims)
  ? parsed.verified_claims
      .map((x) => obj(x))
      .map((x) => ({
        claim: str(x.claim),
        sources: stringArray(x.sources),
        classification: validVerifiedClass(x.classification),
      }))
      .filter((x) => x.claim && x.sources.length > 0 && x.classification)
  : [];

return {
  json: {
    run_id: request.run_id,
    deal_id: request.deal_id,
    company_name: request.company_name,
    timestamp_started: request.timestamp_started,
    source_manifest: request.source_manifest,
    contradiction_output: {
      contradictions,
      verified_claims: verifiedClaims,
    },
    contradiction_retrieval_meta: request.contradiction_retrieval_meta,
    llm_usage: response.usage || {},
    llm_model: response.model || $env.ALICLOUD_MODEL,
  },
};
